    // ----------------- HOME -----------------
    'app/Http/Controllers/HomeController.php' => "<?php\n\nnamespace App\Http\Controllers;\n\nuse Illuminate\Http\Request;\nuse App\Models\{Product, Store};\n\nclass HomeController extends Controller\n{\n    public function index(Request \$request)\n    {\n        // Tampilkan produk terbaru atau unggulan\n        \$featured_products = Product::with(['store', 'category'])->latest()->take(6)->get();\n        if (\$request->wantsJson()) return response()->json(\$featured_products);\n        return view('home', compact('featured_products'));\n    }\n\n    public function sellers(Request \$request)\n    {\n        // Tampilkan daftar UMKM yang sudah diverifikasi\n        \$sellers = Store::where('status_verifikasi', 'disetujui')->with('user')->get();\n        if (\$request->wantsJson()) return response()->json(\$sellers);\n        return view('sellers.index', compact('sellers'));\n    }\n}\n",

    // ----------------- PRODUCT (KATALOG) -----------------
    'app/Http/Controllers/ProductController.php' => "<?php\n\nnamespace App\Http\Controllers;\n\nuse Illuminate\Http\Request;\nuse App\Models\Product;\n\nclass ProductController extends Controller\n{\n    public function index(Request \$request)\n    {\n        \$query = Product::with(['store', 'category']);\n\n        if (\$request->has('kategori')) {\n            \$query->where('id_kategori', \$request->kategori);\n        }\n\n        \$products = \$query->paginate(12);\n        if (\$request->wantsJson()) return response()->json(\$products);\n        return view('products.index', compact('products'));\n    }\n\n    public function show(Request \$request, \$id)\n    {\n        \$product = Product::with(['store', 'category', 'reviews.user'])->findOrFail(\$id);\n        if (\$request->wantsJson()) return response()->json(\$product);\n        return view('products.show', compact('product'));\n    }\n\n    public function search(Request \$request)\n    {\n        \$keyword = \$request->input('q');\n        \$products = Product::with(['store', 'category'])\n            ->where('nama_produk', 'LIKE', \"%{\$keyword}%\")\n            ->orWhereHas('store', function(\$q) use (\$keyword) {\n                \$q->where('nama_toko', 'LIKE', \"%{\$keyword}%\");\n            })\n            ->paginate(12);\n\n        if (\$request->wantsJson()) return response()->json(\$products);\n        return view('products.index', compact('products'));\n    }\n}\n",

    // ----------------- CART -----------------
    'app/Http/Controllers/CartController.php' => "<?php\n\nnamespace App\Http\Controllers;\n\nuse Illuminate\Http\Request;\nuse App\Models\Cart;\nuse Illuminate\Support\Facades\Auth;\n\nclass CartController extends Controller\n{\n    public function index(Request \$request)\n    {\n        \$carts = Cart::where('id_user', Auth::id())->with('product.store')->get();\n        if (\$request->wantsJson()) return response()->json(\$carts);\n        return view('cart.index', compact('carts'));\n    }\n\n    public function store(Request \$request)\n    {\n        \$request->validate([\n            'id_produk' => 'required|exists:products,id_produk',\n            'jumlah' => 'required|integer|min:1'\n        ]);\n\n        // Cek jika produk sudah ada di keranjang\n        \$cart = Cart::where('id_user', Auth::id())->where('id_produk', \$request->id_produk)->first();\n        if (\$cart) {\n            \$cart->update(['jumlah' => \$cart->jumlah + \$request->jumlah]);\n        } else {\n            \$cart = Cart::create([\n                'id_user' => Auth::id(),\n                'id_produk' => \$request->id_produk,\n                'jumlah' => \$request->jumlah\n            ]);\n        }\n\n        if (\$request->wantsJson()) return response()->json(['message' => 'Ditambahkan ke keranjang', 'cart' => \$cart]);\n        return redirect()->back()->with('success', 'Menu ditambahkan ke keranjang');\n    }\n\n    public function update(Request \$request, \$id)\n    {\n        \$cart = Cart::where('id_user', Auth::id())->findOrFail(\$id);\n        \$request->validate(['jumlah' => 'required|integer|min:1']);\n        \$cart->update(['jumlah' => \$request->jumlah]);\n\n        if (\$request->wantsJson()) return response()->json(['message' => 'Keranjang diperbarui', 'cart' => \$cart]);\n        return redirect()->back()->with('success', 'Keranjang diperbarui');\n    }\n\n    public function destroy(Request \$request, \$id)\n    {\n        \$cart = Cart::where('id_user', Auth::id())->findOrFail(\$id);\n        \$cart->delete();\n\n        if (\$request->wantsJson()) return response()->json(['message' => 'Menu dihapus dari keranjang']);\n        return redirect()->back()->with('success', 'Menu dihapus dari keranjang');\n    }\n}\n",

    // ----------------- ORDER & CHECKOUT -----------------
    'app/Http/Controllers/OrderController.php' => "<?php\n\nnamespace App\Http\Controllers;\n\nuse Illuminate\Http\Request;\nuse App\Models\{Order, OrderDetail, Cart, Payment};\nuse Illuminate\Support\Facades\Auth;\nuse Illuminate\Support\Facades\DB;\n\nclass OrderController extends Controller\n{\n    public function index(Request \$request)\n    {\n        \$orders = Order::where('id_user', Auth::id())->with(['store', 'orderDetails.product'])->orderBy('created_at', 'desc')->get();\n        if (\$request->wantsJson()) return response()->json(\$orders);\n        return view('orders.index', compact('orders'));\n    }\n\n    public function store(Request \$request)\n    {\n        // Ambil keranjang user\n        \$carts = Cart::where('id_user', Auth::id())->with('product')->get();\n        if (\$carts->isEmpty()) {\n            if (\$request->wantsJson()) return response()->json(['message' => 'Keranjang kosong'], 400);\n            return redirect()->back()->with('error', 'Keranjang Anda kosong');\n        }\n\n        // Kita kelompokkan pesanan berdasarkan toko (1 pesanan = 1 toko)\n        \$cartsByStore = \$carts->groupBy('product.id_toko');\n        \$createdOrders = [];\n\n        DB::beginTransaction();\n        try {\n            foreach (\$cartsByStore as \$id_toko => \$items) {\n                \$total_harga = \$items->sum(function (\$item) {\n                    return \$item->product->harga * \$item->jumlah;\n                });\n\n                \$order = Order::create([\n                    'id_user' => Auth::id(),\n                    'id_toko' => \$id_toko,\n                    'total_harga' => \$total_harga + 10000, // Misal tambah ongkir statis 10rb\n                    'status_pesanan' => 'menunggu',\n                    'alamat_pengiriman' => Auth::user()->alamat ?? 'Alamat Belum Diatur'\n                ]);\n\n                Payment::create([\n                    'id_pesanan' => \$order->id_pesanan,\n                    'metode_pembayaran' => \$request->input('metode_pembayaran', 'COD'),\n                    'jumlah_pembayaran' => \$order->total_harga,\n                    'status_pembayaran' => 'pending'\n                ]);\n\n                foreach (\$items as \$item) {\n                    OrderDetail::create([\n                        'id_pesanan' => \$order->id_pesanan,\n                        'id_produk' => \$item->id_produk,\n                        'jumlah' => \$item->jumlah,\n                        'harga' => \$item->product->harga,\n                        'subtotal' => \$item->product->harga * \$item->jumlah\n                    ]);\n                }\n                \$createdOrders[] = \$order;\n            }\n            \n            // Kosongkan keranjang setelah checkout\n            Cart::where('id_user', Auth::id())->delete();\n            DB::commit();\n\n            if (\$request->wantsJson()) return response()->json(['message' => 'Checkout berhasil', 'orders' => \$createdOrders], 201);\n            return redirect()->route('orders.index')->with('success', 'Pesanan berhasil dibuat');\n\n        } catch (\Exception \$e) {\n            DB::rollBack();\n            if (\$request->wantsJson()) return response()->json(['message' => 'Terjadi kesalahan sistem', 'error' => \$e->getMessage()], 500);\n            return redirect()->back()->with('error', 'Checkout gagal: ' . \$e->getMessage());\n        }\n    }\n\n    public function show(Request \$request, \$id)\n    {\n        \$order = Order::where('id_user', Auth::id())->with(['store', 'orderDetails.product', 'kurir'])->findOrFail(\$id);\n        if (\$request->wantsJson()) return response()->json(\$order);\n        return view('orders.show', compact('order'));\n    }\n}\n",

